import { describe, expect, it } from 'vitest';
import {
  schwarzschildRadius,
  gravitationalDilationFactor,
  dilationField,
  dilationAtDistance,
  combinedDilation,
  type GravitationalBody,
} from './gravitational-dilation';

describe('schwarzschildRadius', () => {
  it('Sun ≈ 3.12e-13 ly', () => {
    const rs = schwarzschildRadius(1);
    expect(rs).toBeCloseTo(3.12e-13, 15);
  });

  it('Sgr A* (4.29e6 solar masses) ≈ 1.34e-6 ly', () => {
    const rs = schwarzschildRadius(4.29e6);
    expect(rs).toBeCloseTo(1.34e-6, 8);
  });

  it('M87* (6.5e9 solar masses) ≈ 2.03e-3 ly', () => {
    const rs = schwarzschildRadius(6.5e9);
    expect(rs).toBeCloseTo(2.03e-3, 5);
  });
});

describe('gravitationalDilationFactor', () => {
  it('returns 0 at the event horizon (r = r_s)', () => {
    const rs = schwarzschildRadius(1);
    expect(gravitationalDilationFactor(1, rs)).toBe(0);
  });

  it('returns 0 inside the event horizon (r < r_s)', () => {
    const rs = schwarzschildRadius(1);
    expect(gravitationalDilationFactor(1, rs * 0.5)).toBe(0);
  });

  it('at 10·r_s ≈ 0.9487 (clocks at ~95% speed)', () => {
    const rs = schwarzschildRadius(1);
    const factor = gravitationalDilationFactor(1, 10 * rs);
    expect(factor).toBeCloseTo(0.9487, 4);
  });

  it('at 100·r_s ≈ 0.995 (clocks at ~99.5% speed)', () => {
    const rs = schwarzschildRadius(1);
    const factor = gravitationalDilationFactor(1, 100 * rs);
    expect(factor).toBeCloseTo(0.995, 3);
  });

  it('at very large distance approaches 1.0', () => {
    const factor = gravitationalDilationFactor(1, 1e10);
    expect(factor).toBeCloseTo(1.0, 10);
  });
});

describe('dilationField', () => {
  const sun: GravitationalBody = {
    id: 'sun',
    label: 'Sun',
    massSolar: 1,
    positionLy: { x: 0, y: 0, z: 0 },
  };

  it('produces the requested number of rings', () => {
    const field = dilationField(sun, 5);
    expect(field.rings).toHaveLength(5);
    expect(field.source).toBe('GnosisGravitationalDilation');
  });

  it('defaults to 10 rings', () => {
    const field = dilationField(sun);
    expect(field.rings).toHaveLength(10);
  });

  it('rings are in ascending radius order', () => {
    const field = dilationField(sun, 8);
    for (let i = 1; i < field.rings.length; i++) {
      expect(field.rings[i].radiusLy).toBeGreaterThan(field.rings[i - 1].radiusLy);
    }
  });

  it('dilation factors increase with radius', () => {
    const field = dilationField(sun, 8);
    for (let i = 1; i < field.rings.length; i++) {
      expect(field.rings[i].dilationFactor).toBeGreaterThanOrEqual(field.rings[i - 1].dilationFactor);
    }
  });

  it('schwarzschildRadiusLy matches eventHorizonRadiusLy for non-rotating body', () => {
    const field = dilationField(sun);
    expect(field.schwarzschildRadiusLy).toBe(field.eventHorizonRadiusLy);
  });
});

describe('dilationAtDistance', () => {
  it('returns correct slowdown percent', () => {
    const rs = schwarzschildRadius(1);
    const result = dilationAtDistance(1, 10 * rs);
    expect(result.dilationFactor).toBeCloseTo(0.9487, 4);
    expect(result.timeSlowdownPercent).toBeCloseTo(5.13, 1);
  });
});

describe('combinedDilation', () => {
  it('at large distance from all bodies ≈ 1.0', () => {
    const bodies: GravitationalBody[] = [
      { id: 'a', label: 'Star A', massSolar: 1, positionLy: { x: 0, y: 0, z: 0 } },
      { id: 'b', label: 'Star B', massSolar: 10, positionLy: { x: 100, y: 0, z: 0 } },
    ];
    const farPoint = { x: 1e6, y: 1e6, z: 1e6 };
    const factor = combinedDilation(bodies, farPoint);
    expect(factor).toBeCloseTo(1.0, 8);
  });

  it('Earth surface dilation from Sun is extremely close to 1', () => {
    const sun: GravitationalBody = {
      id: 'sun',
      label: 'Sun',
      massSolar: 1,
      positionLy: { x: 0, y: 0, z: 0 },
    };
    // Earth-Sun distance ≈ 0.0000158 ly
    const earthPoint = { x: 0.0000158, y: 0, z: 0 };
    const factor = combinedDilation([sun], earthPoint);
    expect(factor).toBeGreaterThan(0.99999999);
    expect(factor).toBeLessThan(1.0);
  });
});
